// 1. Create the Observer
const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    // Is the element visible on screen right now?
    if (entry.isIntersecting) {
      entry.target.classList.add('fade-in');
      // Once it's loaded, stop watching it to save memory
      observer.unobserve(entry.target);
    }
  });
});

// 2. Tell the observer which elements to watch
const hiddenImages = document.querySelectorAll('.lazy-image');
hiddenImages.forEach(img => observer.observe(img));
